return items.map(item => {
  const a = item.json;
  return {
    json: {
      id:              a.id,
      athleteId:       a.icu_athlete_id,
      date:            new Date(a.start_date),         // ISO 8601
      type:            a.type,
      duration:        a.elapsed_time,       // seconds
      distance:        a.distance,           // meters (or null)
      calories:        a.calories,
      trimp:           a.trimp,
      ctl:             a.icu_ctl,
      atl:             a.icu_atl,
      rampRate:        a.rampRate ?? (a.icu_ctl - a.icu_atl),
      avgHeartRate:    a.average_heartrate,
      maxHeartRate:    a.max_heartrate,
      interval_summary: a.interval_summary,  // e.g. ["1x...","3x..."]
      sportInfo:       a.sportInfo           // you can leave the array or map to just types
    }
  };
});

return items.map(item => {
  const w = item.json;
  return {
    json: {
      id:         w.id,                            // e.g. "2025-07-10"
      athleteId:  w.icu_athlete_id,                // your athlete key
      date:       new Date(w.updated),                       // ISO timestamp of the record
      ctl:        w.ctl,                           // chronic training load
      atl:        w.atl,                           // acute training load
      rampRate:   w.rampRate ?? (w.ctl - w.atl),   // change in load
      ctlLoad:    w.ctlLoad,                       // daily CTL “load”
      atlLoad:    w.atlLoad,                       // daily ATL “load”
      restingHR:  w.restingHR,                     // recovery HR
      hrv:        w.hrv,                           // HRV
      sleepScore: w.sleepScore,                    // sleep quality
      steps:      w.steps,                         // daily step count
      weight:     w.weight                         // body weight (if available)
    }
  };
});

// Function node: Compute weekly_metrics for the CURRENT week (Monday–Sunday)
// Input: one item whose JSON has { activities: [...], wellness: [...] }

const { activities: acts, wellness: well } = items[0].json;

// 1️⃣ Compute current week boundaries (Monday 00:00 to Sunday 23:59:59)
const today = new Date();
const day = today.getDay();               // 0=Sun, 1=Mon, … 6=Sat
const diffToMonday = (day + 6) % 7;
const monday = new Date(today);
monday.setDate(today.getDate() - diffToMonday);
monday.setHours(0,0,0,0);
const sunday = new Date(monday);
sunday.setDate(monday.getDate() + 6);
sunday.setHours(23,59,59,999);

// 2️⃣ Helper: average over non-null
const avg = arr => arr.length
  ? arr.reduce((sum, v) => sum + v, 0) / arr.length
  : 0;

// 3️⃣ Filter this week’s activities
const inWeek = a => {
  const d = new Date(a.start_date);
  return d >= monday && d <= sunday;
};
const weekActs = acts.filter(inWeek);

// 4️⃣ Run, ride & strength metrics
const runActs      = weekActs.filter(a => a.type === 'Run');
const rideActs     = weekActs.filter(a => /Ride/.test(a.type));
const strengthActs = weekActs.filter(a => a.type === 'WeightTraining');

const runCount     = runActs.length;
const runDistance  = runActs.reduce((s,a) => s + (a.distance||0), 0);
const runTime      = runActs.reduce((s,a) => s + (a.elapsed_time||0), 0);

const rideCount    = rideActs.length;
const rideDistance = rideActs.reduce((s,a) => s + (a.distance||0), 0);
const rideTime     = rideActs.reduce((s,a) => s + (a.elapsed_time||0), 0);
const rideTrimp    = rideActs.reduce((s,a) => s + (a.trimp||0), 0);

const strengthCount = strengthActs.length;
const strengthTrimp = strengthActs.reduce((s,a) => s + (a.trimp||0), 0);

// 5️⃣ Session‐type counts by keyword in activity name
const vo2Sessions   = runActs.filter(a => /vo2/i.test(a.name)).length;
const tempoSessions = runActs.filter(a => /tempo|threshold|umbral/i.test(a.name)).length;
const longRuns      = runActs.filter(a => /long/i.test(a.name)).length;

// 6️⃣ Wellness this week (filter by id = YYYY-MM-DD)
const wellWeek = well.filter(w => {
  const d = new Date(w.id);
  return d >= monday && d <= sunday;
});

const ctlMean        = avg(wellWeek.map(w=>w.ctl||0));
const atlMean        = avg(wellWeek.map(w=>w.atl||0));
const rampRateMean   = avg(wellWeek.map(w=>w.rampRate||0));
const restHrMean     = avg(wellWeek.map(w=>w.restingHR||0));
const stepsMean      = avg(wellWeek.map(w=>w.steps||0));
const sleepScoreMean = avg(wellWeek.map(w=>w.sleepScore||0));
const hrvMean        = avg(wellWeek.map(w=>w.hrv||0));

// 7️⃣ Identify athleteId (from any activity)
const athleteId = acts.length
  ? acts[0].icu_athlete_id
  : null;

// 8️⃣ Build weekly_metrics record
const weekStart = monday.toISOString().slice(0,10);
const weekEnd   = sunday.toISOString().slice(0,10);
const now       = new Date().toISOString();

return [{
  json: {
    athleteId,
    weekStart,
    weekEnd,

    runCount,
    runDistance,
    runTime,

    rideCount,
    rideDistance,
    rideTime,
    rideTrimp,

    vo2Sessions,
    tempoSessions,
    longRuns,

    strengthCount,
    strengthTrimp,

    ctlMean,
    atlMean,
    rampRateMean,

    restHrMean,
    stepsMean,
    sleepScoreMean,
    hrvMean,

    createdAt: now,
    updatedAt: now
  }
}];

// El primer ítem es el current
const current = items[0].json;

// Los siguientes ítems son tu histórico
const pastWeeks = items.slice(1).map(i => i.json);

return [{
  json: {
    current,       // todas las métricas y el prompt de esta semana
    history: pastWeeks  // tu histórico ya preparado
  }
}];

// in a Function node (Run Once for All Items)

const activities = $items("GET Activities").map(item => item.json);
const wellness   = $items("GET Wellness"  ).map(item => item.json);

return [
  {
    json: {
      activities,
      wellness
    }
  }
];

/**
 * Prompt Builder para generar el JSON limpio que le enviaremos a OpenAI
 * Incluye semana, fechas y solicita al modelo los campos necesarios.
 */

// —————————————— CONFIGURACIÓN ——————————————

// Fecha de inicio de tu plan (puedes ajustarla)
const programStartDate = new Date('2025-07-19');

// Fecha de la competición
const raceDate = new Date('2026-02-15');

// ——————————— CÁLCULOS DE FECHAS ———————————

const today = new Date();
const msPerWeek = 7 * 24 * 60 * 60 * 1000;
const weeksSinceStart = Math.floor((today - programStartDate) / msPerWeek) + 1;
const weeksToRace = Math.ceil((raceDate - today) / msPerWeek);
const totalPlanWeeks = weeksSinceStart + weeksToRace;

// —————————— DETERMINACIÓN DE FASE ——————————

let phaseName, phaseNote;
if (weeksSinceStart <= Math.floor(totalPlanWeeks * 0.3)) {
  phaseName = 'Base';
  phaseNote = 'Rodajes suaves y fuerza general.';
} else if (weeksSinceStart <= Math.floor(totalPlanWeeks * 0.7)) {
  phaseName = 'Desarrollo';
  phaseNote = 'Interválicos, tempo runs y fuerza específica.';
} else if (weeksToRace > 2) {
  phaseName = 'Específica';
  phaseNote = 'Ritmo objetivo, simulaciones de competición.';
} else {
  phaseName = 'Taper';
  phaseNote = 'Reducción de carga manteniendo chispa.';
}

// —————————— DESCOMPOSICIÓN DE DATOS ——————————

let current = {};
let rawHistory = [];
let sourceActivities = [];
let sourceWellness = [];
let sourceHeartRateSync = {};
let sourceRunId = null;

for (const item of items) {
  const payload = item && item.json && typeof item.json === 'object' ? item.json : {};

  if (Object.keys(current).length === 0 && payload.current && typeof payload.current === 'object') {
    current = payload.current;
  }

  if ((!Array.isArray(rawHistory) || rawHistory.length === 0) && Array.isArray(payload.history)) {
    rawHistory = payload.history;
  }

  if (Array.isArray(payload.activities) && payload.activities.length >= sourceActivities.length) {
    sourceActivities = payload.activities;
  }

  if (Array.isArray(payload.wellness) && payload.wellness.length >= sourceWellness.length) {
    sourceWellness = payload.wellness;
  }

  if (Object.keys(sourceHeartRateSync).length === 0 && payload.heartRateSync && typeof payload.heartRateSync === 'object') {
    sourceHeartRateSync = payload.heartRateSync;
  }

  if (!sourceRunId && typeof payload.runId === 'string' && payload.runId.trim()) {
    sourceRunId = payload.runId.trim();
  }
}

const history = Array.isArray(rawHistory)
  ? rawHistory
      .sort((a, b) => b.weekStart.localeCompare(a.weekStart))
      .slice(0, 4)
  : [];

const activities = sourceActivities;
const wellness = sourceWellness;

// —————————— EXTRACCIÓN DE ZONAS DE FC ——————————

const DEFAULT_FCMAX = 202;
const toNum = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
};

const recordedMaxHR = Math.max(
  ...activities.map(a => a.max_heartrate || 0).filter(hr => hr > 0)
);

const heartRateSync = sourceHeartRateSync && typeof sourceHeartRateSync === 'object'
  ? sourceHeartRateSync
  : {};
const hrMax = toNum(heartRateSync.hrMax);
const hrRest = toNum(heartRateSync.hrRest);
const lthr = toNum(heartRateSync.lthr);
const zoneMethod = typeof heartRateSync.zoneMethod === 'string' ? heartRateSync.zoneMethod : null;
const computedZones = heartRateSync.computedZones && typeof heartRateSync.computedZones === 'object'
  ? heartRateSync.computedZones
  : null;
const zonesUpdated = Boolean(heartRateSync.zonesUpdated);
const zoneUpdateNotice = typeof heartRateSync.zoneUpdateNotice === 'string' ? heartRateSync.zoneUpdateNotice : null;
const hrSyncLog = heartRateSync.hrSyncLog && typeof heartRateSync.hrSyncLog === 'object'
  ? heartRateSync.hrSyncLog
  : null;

const fcMax = hrMax ?? (recordedMaxHR >= 190 ? recordedMaxHR : DEFAULT_FCMAX);
const zoneSummary = computedZones
  ? ['z1', 'z2', 'z3', 'z4', 'z5']
      .map((key) => {
        const zone = computedZones[key];
        if (!zone || zone.min == null || zone.max == null) return null;
        return `${key.toUpperCase()} ${zone.min}-${zone.max}`;
      })
      .filter(Boolean)
      .join(', ')
  : null;

// —————————— HELPERS ——————————

const avg = arr => arr.length ? arr.reduce((sum, v) => sum + v, 0) / arr.length : 0;
const fmt = x   => x != null ? x.toFixed(1) : '—';

// —————————— MÉTRICAS SEMANA ACTUAL ——————————

const { weekStart, weekEnd } = current;
const ctlActs    = avg( activities.map(a => a.icu_ctl      || 0) );
const atlActs    = avg( activities.map(a => a.icu_atl      || 0) );
const rampActs   = avg( activities.map(a => a.icu_rampRate || 0) );
const totalTrimp = activities.reduce((s,a) => s + (a.trimp || 0), 0);

const restVals = [...activities, ...wellness]
  .map(o => o.restingHR).filter(v => v != null);
const stepVals = [...activities, ...wellness]
  .map(o => o.steps).filter(v => v != null);

const restHR   = avg(restVals);
const steps    = avg(stepVals);
const hrvWel   = avg( wellness.map(w => w.hrv        || 0) );
const sleepWel = avg( wellness.map(w => w.sleepScore || 0) );

// —————————— CONSTRUCCIÓN DEL PROMPT (FORZAR JSON PURA) ——————————

const prompt = `
// PROMPT_BEGIN
Eres mi coach experto en medio maratón (método noruego, híbrido fuerza+carrera).

Contexto:
- Mitja Marató Barcelona (15‑02‑2026), objetivo 1h45m (~4:59/km).
- Empezamos el plan el ${programStartDate.toISOString().slice(0,10)}, esta es la semana **${weeksSinceStart}** de un plan de **${totalPlanWeeks}** semanas.
- Quedan **${weeksToRace}** semanas → Fase **${phaseName}**: ${phaseNote}

Resumen ${weekStart} → ${weekEnd}:
• CTL avg: ${fmt(ctlActs)}, ATL avg: ${fmt(atlActs)}, RampRate avg: ${fmt(rampActs)}
• TRIMP total: ${fmt(totalTrimp)}
• FC reposo medio: ${fmt(restHR)} bpm, Pasos/día medio: ${fmt(steps)}
• HRV avg: ${fmt(hrvWel)}, SleepScore avg: ${fmt(sleepWel)}

Historial (4 semanas anteriores):
${history.map(h =>
  `- Semana ${h.weekStart}: ${fmt(h.runDistance/1000)} km · ATL ${fmt(h.atlMean)} · RampRate ${fmt(h.rampRateMean)} · RHR ${fmt(h.restHrMean)}`
).join('\n')}


Por favor genera mi plan PARA LA PRÓXIMA SEMANA siguiendo el método noruego:
- Indica fase del plan y el objetivo de la semana.
- **Gimnasio**: Mar, Jue y Sáb (orden: Pecho y brazos, Espalda y hombros, Piernas).
- **Running** según carga (CTL, ATL, TRIMP, HRV/Sueño):
  1. Sesión VO₂ máx  
  2. Sesión tempo/umbral  
  3. Tirada larga aeróbica  
  4. Easy/recovery  


**IMPORTANTE**:  
- Gimnasio a las 12–13h, calcula recuperación y planifica alrededor.  
- Usa **zonas de FC Garmin (Z1–Z5)** con método ${zoneMethod || '%HRR'} y FCmáx=${fcMax} bpm; indica % y rango de bpm.  
- FC reposo de referencia: ${hrRest != null ? `${hrRest} bpm` : 'no disponible'}.
- LTHR de referencia: ${lthr != null ? `${lthr} bpm` : 'no disponible'}.
- Zonas objetivo: ${zoneSummary || 'calcular con %HRR (Karvonen) cuando falten zonas precomputadas'}.



SALIDA (OBLIGATORIA):

- Devuelve exclusivamente un JSON válido y minificado en UNA sola línea (sin texto extra, sin bloques de código, sin comentarios).
- Sustituye en todos los textos: &→&amp;, <→&lt;, >→&gt;.
- La respuesta empieza con { y termina con }.
- Presupuesto total estricto: ≤ 2600 caracteres.

Límites obligatorios por campo (no exceder):
- activityPlan.nextWeek.phase: 1-32 caracteres
- activityPlan.nextWeek.objective: 1-120 caracteres
- activityPlan.days[].activity: 1-24 caracteres
- activityPlan.days[].distance_time: 1-24 caracteres
- activityPlan.days[].intensity: 1-32 caracteres
- activityPlan.days[].goal: 1-72 caracteres
- activityPlan.days[].note: 0-80 caracteres (opcional)
- justification: array de 2 a 3 items
- justification[]: 1-110 caracteres por item

Estructura EXACTA con 7 objetos en days (uno por cada día de la semana). Si te quedas sin espacio, reformula más corto sin omitir campos obligatorios.

\`\`\`json
{
  "schema_version": "1.0",
  "activityPlan": {
    "nextWeek": {
      "phase": string,
      "objective": string,
      "weekStart": string,   // e.g. "2025-07-14"
      "weekEnd":   string    // e.g. "2025-07-20"
    },
    "days": [
      {
        "day": string,         // Nombre en español, ej. "Lunes"
        "date": string,        // Fecha concreta, ej. "2025-07-14"
        "activity": string,
        "distance_time": string,
        "intensity": string,
        "goal": string,
        "note": string
      }
      // …un objeto por cada día de la semana
    ]
  },
  "justification": [ string, … ]
}
\`\`\`
// PROMPT_END
`.trim();

// —————————— RETORNO ——————————

const runId = sourceRunId || `${new Date().toISOString()}-${Math.random().toString(36).slice(2, 8)}`;
const PROMPT_VERSION = "2026-02-19";
// Bump PROMPT_VERSION whenever the prompt template changes.
const modelId = "gpt-5";
const createdAt = new Date().toISOString();

return [{
  json: {
    runId,
    promptVersion: PROMPT_VERSION,
    modelId,
    createdAt,
    prompt,
    metrics: {
      programStartDate: programStartDate.toISOString().slice(0,10),
      weeksSinceStart,
      totalPlanWeeks,
      weeksToRace,
      phaseName,
      weekStart,
      weekEnd,
      ctlActs,
      atlActs,
      rampActs,
      totalTrimp,
      restHR,
      steps,
      hrvWel,
      sleepWel,
      fcMax,
      hrMax,
      hrRest,
      lthr,
      zoneMethod,
      zonesUpdated
    },
    heartRate: {
      hrMax,
      hrRest,
      lthr,
      zoneMethod,
      computedZones,
      zonesUpdated,
      zoneUpdateNotice,
      hrSyncLog,
    },
    history,
    activities,
    wellness
  }
}];

