const TEMPLATE_VERSION = 'telegram-v2.2';

const DEFAULT_CHAT_ID = '730354404';

const isObject = (value) => value !== null && typeof value === 'object' && !Array.isArray(value);

const parseContent = (input) => {
  if (typeof input !== 'string') {
    return input;
  }
  try {
    return JSON.parse(input);
  } catch {
    return null;
  }
};

const payloads = items
  .map((item) => (item && item.json ? item.json : {}))
  .filter((payload) => payload && Object.keys(payload).length > 0);

const getNodeItemsSafe = (nodeName) => {
  try {
    const nodeItems = $items(nodeName);
    return Array.isArray(nodeItems) ? nodeItems : [];
  } catch {
    return [];
  }
};

const fallbackNodeNames = [
  'Build Run Event (success)',
  'Validate WeeklyPlan (attempt 0)',
];

const fallbackNodeCounts = {};
const fallbackPayloads = [];
for (const nodeName of fallbackNodeNames) {
  const nodeItems = getNodeItemsSafe(nodeName);
  fallbackNodeCounts[nodeName] = nodeItems.length;
  for (const nodeItem of nodeItems) {
    const payload = nodeItem && nodeItem.json ? nodeItem.json : {};
    if (payload && Object.keys(payload).length > 0) {
      fallbackPayloads.push(payload);
    }
  }
}

const allPayloads = [...payloads, ...fallbackPayloads];

const parsePlanCandidate = (payload) => {
  const raw = Array.isArray(payload.choices)
    ? payload.choices[0] && payload.choices[0].message
      ? payload.choices[0].message.content
      : null
    : payload;
  const parsed = parseContent(raw);
  return isObject(parsed) ? parsed : null;
};

const parsedCandidates = allPayloads
  .map((payload) => parsePlanCandidate(payload))
  .filter((payload) => payload !== null);

const content = parsedCandidates.find((payload) => isObject(payload.activityPlan)) || null;
if (!content) {
  const inboundKeys = payloads
    .slice(0, 3)
    .map((payload) => Object.keys(payload).slice(0, 8));
  throw new Error(
    `Missing or invalid activityPlan in response. inbound_payloads=${payloads.length}; fallback_counts=${JSON.stringify(fallbackNodeCounts)}; inbound_keys=${JSON.stringify(inboundKeys)}`,
  );
}

const supplementalPayload = {};

const plan = content.activityPlan;
const nextWeek = isObject(plan.nextWeek) ? plan.nextWeek : {};
const days = Array.isArray(plan.days) ? plan.days : [];
const justifications = Array.isArray(content.justification) ? content.justification : [];

const getVar = (key) => {
  if (typeof $vars !== 'undefined' && $vars[key] != null) {
    return String($vars[key]);
  }
  if (typeof process !== 'undefined' && process.env && process.env[key] != null) {
    return String(process.env[key]);
  }
  return '';
};

const isTruthy = (value) => ['1', 'true', 'yes', 'on'].includes(String(value).toLowerCase());

const previewEnabled = isTruthy(getVar('RC_TELEGRAM_PREVIEW_MODE'));
const previewChatRaw = getVar('RC_TELEGRAM_PREVIEW_CHAT_ID').trim();
if (previewEnabled && !previewChatRaw) {
  throw new Error('RC_TELEGRAM_PREVIEW_CHAT_ID is required when RC_TELEGRAM_PREVIEW_MODE is enabled.');
}
const targetChatId = previewEnabled ? previewChatRaw : DEFAULT_CHAT_ID;

const runContextItems = $items('Prompt Builder');
const runContext = runContextItems.length ? runContextItems[0].json : {};
const metrics = isObject(runContext.metrics) ? runContext.metrics : {};
const history = Array.isArray(runContext.history) ? runContext.history : [];

const heartRate = isObject(runContext.heartRate) ? runContext.heartRate : {};
const hrSyncLog = isObject(heartRate.hrSyncLog) ? heartRate.hrSyncLog : {};
const zonesUpdated = Boolean(heartRate.zonesUpdated);
const toHrString = (value) => (value === null || value === undefined || value === '' ? '-' : String(Math.round(Number(value))));
const zoneUpdateNotice = zonesUpdated
  ? (typeof heartRate.zoneUpdateNotice === 'string' && heartRate.zoneUpdateNotice.trim()
      ? heartRate.zoneUpdateNotice.trim()
      : `🛠️ Zonas actualizadas: Max ${toHrString(hrSyncLog.hrMax_old)}→${toHrString(hrSyncLog.hrMax_new)} · Reposo ${toHrString(hrSyncLog.hrRest_old)}→${toHrString(hrSyncLog.hrRest_new)} · Umbral ${toHrString(hrSyncLog.lthr_old)}→${toHrString(hrSyncLog.lthr_new)}`)
  : null;


const valueOr = (value, fallback = '--') => {
  if (value === null || value === undefined) return fallback;
  const text = String(value).trim();
  return text || fallback;
};

const esc = (value) => String(value)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const num = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
};

const mean = (values) => {
  const valid = values.map(num).filter((value) => value !== null);
  if (!valid.length) return null;
  return valid.reduce((sum, value) => sum + value, 0) / valid.length;
};

const fmt = (value, suffix = '') => (value === null ? '--' : `${value.toFixed(1)}${suffix}`);
const pct = (value) => (value === null ? '--' : `${(value * 100).toFixed(0)}%`);

const intOrZero = (value) => {
  const parsed = Number.parseInt(value, 10);
  return Number.isFinite(parsed) ? parsed : 0;
};

const normalizeDay = (value) => String(value || '')
  .toLowerCase()
  .replace(/[áàä]/g, 'a')
  .replace(/[éèë]/g, 'e')
  .replace(/[íìï]/g, 'i')
  .replace(/[óòö]/g, 'o')
  .replace(/[úùü]/g, 'u')
  .replace(/ñ/g, 'n');

const dayOrder = {
  lunes: 0,
  monday: 0,
  martes: 1,
  tuesday: 1,
  miercoles: 2,
  wednesday: 2,
  jueves: 3,
  thursday: 3,
  viernes: 4,
  friday: 4,
  sabado: 5,
  saturday: 5,
  domingo: 6,
  sunday: 6,
};

const sortedDays = [...days].sort((a, b) => {
  const aOrder = dayOrder[normalizeDay(a.day)];
  const bOrder = dayOrder[normalizeDay(b.day)];
  const safeA = aOrder === undefined ? 99 : aOrder;
  const safeB = bOrder === undefined ? 99 : bOrder;
  if (safeA !== safeB) return safeA - safeB;
  return String(a.date || '').localeCompare(String(b.date || ''));
});

const ctlNow = num(metrics.ctlActs);
const atlNow = num(metrics.atlActs);
const rampNow = num(metrics.rampActs);
const trimpNow = num(metrics.totalTrimp);
const restNow = num(metrics.restHR);
const hrvNow = num(metrics.hrvWel);
const sleepNow = num(metrics.sleepWel);
const stepsNow = num(metrics.steps);

const lastWeekSummaryLines = [];
if (ctlNow !== null || atlNow !== null || rampNow !== null) {
