  activity: 24,
  distance_time: 24,
  intensity: 32,
  goal: 72,
  note: 80,
  justification: 110,
};

const reqMaxLen = (obj, key, path, maxLen) => {
  const value = obj ? obj[key] : undefined;
  if (typeof value !== 'string') {
    errors.push(`${path}.${key} must be string`);
    return false;
  }
  const trimmed = value.trim();
  if (!trimmed) {
    errors.push(`${path}.${key} missing`);
    return false;
  }
  if (trimmed.length > maxLen) {
    errors.push(`${path}.${key} too long (${trimmed.length} > ${maxLen})`);
