const envLabel = sanitizeLabel(getVar('RC_METRICS_ENV').trim() || 'prod');
const metricName = 'running_coach_run_timestamp_seconds';
const workflow = sanitizeLabel('running_coach');
const status = sanitizeLabel('failure');
const timestampSec = Math.floor(Date.now() / 1000);
const metricBody = `${metricName} ${timestampSec}\n`;
const root = baseUrl.replace(/\/+$/, '');
const metricsEndpoint = `${root}/metrics/job/n8n_workflows/workflow/${encodeURIComponent(workflow)}/status/${encodeURIComponent(status)}/env/${encodeURIComponent(envLabel)}`;

return [{
  json: {
    workflow,
    status,
    env: envLabel,
    metricName,
    timestampSec,
    metricBody,
    metricsEndpoint,
  }
}];
